// Thin wrapper around the vendored NoSleep.js (global `NoSleep`), which
// itself uses the native Screen Wake Lock API when available (including
// reacquiring it on visibilitychange) and falls back to a silent looping
// video for browsers without the API.
//
// On iOS, NoSleep.js picks native Wake Lock exclusively once it detects
// `"wakeLock" in navigator` (true since iOS 16.4) and never sets up its
// own video fallback there. In practice iOS's native Wake Lock has real
// reliability gaps — Low Power Mode, installed/standalone PWA mode, and
// brief backgrounding can all leave the screen dimming even though the
// request() call succeeded. So on iOS specifically we *also* run the
// classic silent-looping-video trick in parallel as a redundant safety
// net, using the same tiny data-URI video NoSleep.js itself embeds.

import { isIos } from './install-prompt.js';

const SILENT_MP4 = 'data:video/mp4;base64,';

let instance = null;
let active = false;
let videoEl = null;

function getInstance() {
  if (!instance) instance = new NoSleep();
  return instance;
}

function ensureVideoEl() {
  if (videoEl) return videoEl;
  const v = document.createElement('video');
  v.muted = true;
  v.loop = true;
  v.setAttribute('muted', '');
  v.setAttribute('playsinline', '');
  v.setAttribute('title', 'Keep screen awake');
  v.style.cssText = 'position:fixed;width:1px;height:1px;opacity:0;pointer-events:none;';
  const source = document.createElement('source');
  source.src = SILENT_MP4;
  source.type = 'video/mp4';
  v.appendChild(source);
  document.body.appendChild(v);
  videoEl = v;
  return v;
}

function resumeVideoIfActive() {
  if (active && videoEl && document.visibilityState === 'visible') {
    videoEl.play().catch(() => {});
  }
}

document.addEventListener('visibilitychange', resumeVideoIfActive);

export async function acquire() {
  active = true;
  try {
    await getInstance().enable();
  } catch {
    // Some browsers reject without a user gesture; the caller also retries
    // this from click handlers, so a failed silent attempt is non-fatal.
  }
  if (isIos()) {
    try {
      await ensureVideoEl().play();
    } catch {
      // Also needs a user gesture on first attempt; visibilitychange and
      // the caller's gesture-backed retry cover this.
    }
  }
}

export function release() {
  active = false;
  if (instance) instance.disable();
  if (videoEl) videoEl.pause();
}

export function isActive() {
  return active;
}
